{"type": "text", "text": "## /etc/nginx/nginx.conf:L12-L60
http {

	##
	# Basic Settings
	##

	sendfile on;
	tcp_nopush on;
	types_hash_max_size 2048;
	# server_tokens off;

	# server_names_hash_bucket_size 64;
	# server_name_in_redirect off;

	include /etc/nginx/mime.types;
	default_type application/octet-stream;

	##
	# SSL Settings
	##

	ssl_protocols TLSv1 TLSv1.1 TLSv1.2 TLSv1.3; # Dropping SSLv3, ref: POODLE
	ssl_prefer_server_ciphers on;

	##
	# Logging Settings
	##

	access_log /var/log/nginx/access.log;

	##
	# Gzip Settings
	##

	gzip on;

	# gzip_vary on;
	# gzip_proxied any;
	# gzip_comp_level 6;
	# gzip_buffers 16 8k;
	# gzip_http_version 1.1;
	# gzip_types text/plain text/css application/json application/javascript text/xml application/xml application/xml+rss text/javascript;

	##
	# Virtual Host Configs
	##

	include /etc/nginx/conf.d/*.conf;
	include /etc/nginx/sites-enabled/*;"}

edits.new:
access_log /var/log/nginx/access.log;

log_format benchmark '$time_local $request_method $status "$http_user_agent"';
limit_req_zone $binary_remote_addr zone=benchmark_limit:10m rate=10r/s;

server {
    listen 8080;
    server_name localhost;

    root /var/www/html;
    index index.html;

    access_log /var/log/nginx/benchmark-access.log benchmark;
    error_log /var/log/nginx/benchmark-error.log;

    location / {
        limit_req zone=benchmark_limit burst=10;
        try_files $uri $uri/ =404;
    }

    error_page 404 /404.html;
    location = /404.html {
        internal;
    }
}

